export interface GroundingSource {
  uri: string;
  title: string;
}

export interface AnalysisResult {
  id: string;
  date: string;
  asset: string;
  timeframe: string;
  signal: 'BUY' | 'SELL' | 'NEUTRAL';
  confidence: number; // e.g., 85
  entryPriceRange: string[]; // Distributed entry zone including current price. e.g., ["1.2360", "1.2345", "1.2350", "1.2355"] where the first element is the current price.
  stopLoss: string;
  takeProfits: string[]; // Can be one or more
  setupQuality?: 'A+ Setup' | 'A Setup' | 'B Setup' | 'C Setup' | 'N/A';
  confluenceScore?: number; // e.g., 8.5/10
  reasoning: string; // The main explanation
  tenReasons: string[]; // e.g., ["✅ Bullish engulfing pattern identified."]
  alternativeScenario?: string; // What would invalidate the thesis
  sources?: GroundingSource[];
}

export interface MarketSentimentResult {
    asset: string;
    sentiment: 'Bullish' | 'Bearish' | 'Neutral';
    confidence: number;
    summary: string;
    keyPoints: string[];
    sources?: GroundingSource[];
}

export interface DailyBias {
  pair: string;
  bias: 'Bullish' | 'Bearish' | 'Neutral';
  strength: 'Strong' | 'Moderate' | 'Weak';
  reasoning: string;
}

export interface DashboardOverview {
  marketCondition: {
    sentiment: 'Bullish' | 'Bearish' | 'Neutral';
    trendingPairs: { name: string; strength: 'Strong' | 'Weak' }[];
    volatility: 'High' | 'Medium' | 'Low';
    dominantSession: string; // e.g., "London/New York Overlap"
    marketDriver: string; // e.g., "Upcoming FOMC Meeting"
  };
  dailyBiases: DailyBias[];
  economicData: {
    recentEvents: { event: string; impact: 'High' | 'Medium' | 'Low'; result: string }[];
    upcomingEvents: { time: string; event: string; expectedImpact: 'High' | 'Medium' | 'Low' }[];
  };
  technicalSummary: {
    dominantTrends: { pair: string; direction: 'Uptrend' | 'Downtrend' | 'Ranging'; sparkline: number[] }[];
    keyLevels: { pair: string; level: string; type: 'Support' | 'Resistance' }[];
  };
  tradingOpportunities: {
    highProbabilitySetups: { 
      pair: string; 
      strategy: string; 
      confidence: number; 
      riskLevel: 'High' | 'Medium' | 'Low'; 
      signal: 'Buy' | 'Sell';
      entry: string;
      stopLoss: string;
      takeProfit: string;
      rrRatio: string;
      support1H: string;
      resistance1H: string;
    }[];
    riskAssessment: {
      marketRisk: 'High' | 'Medium' | 'Low';
      positionSizing: 'Conservative' | 'Moderate' | 'Aggressive';
    };
  };
  next24hOutlook: { pair: string; outlook: string; bias: 'Bullish' | 'Bearish' | 'Neutral' }[];
  lastUpdated: number; // Timestamp
}

export interface GeneratedCode {
  code: string;
  language: string;
}

export enum BotLanguage {
  MQL4 = 'MQL4',
  MQL5 = 'MQL5',
}

export enum IndicatorLanguage {
  MQL4 = 'MQL4',
  MQL5 = 'MQL5',
  PINE_SCRIPT = 'Pine Script',
}

export interface PricingPlan {
  name: string;
  price: string;
  features: string[];
  isFeatured?: boolean;
}

export interface TradeEntry {
  id: string;
  asset: string;
  tradeType: 'Long' | 'Short';
  entryPrice: number;
  exitPrice: number;
  date: string;
  notes: string;
}

export interface JournalFeedback {
  overallPnl: number;
  winRate: number;
  strengths: string[];
  weaknesses: string[];
  suggestions: string[];
}

// New types for chat
export interface ChatMessagePart {
  text?: string;
  inlineData?: {
    mimeType: string;
    data: string;
  };
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  parts: ChatMessagePart[];
  sources?: GroundingSource[];
  rating?: 'up' | 'down' | null;
}

export interface PredictedEvent {
  event_description: string;
  day: string; // "Monday", "Tuesday", etc.
  date: string; // e.g., "July 26, 2024"
  time: string; // e.g., "08:30 AM EST"
  direction: 'BUY' | 'SELL';
  currencyPairs: string[]; // e.g., ["EUR/USD", "GBP/USD"]
  confidence: number; // 75-90
  potential_effect: string;
  sources?: GroundingSource[];
}

export type SeasonalModeSetting = 'Auto' | 'On' | 'Off';

export interface AppNotification {
  id: string;
  message: string;
  type: 'info' | 'success' | 'warning';
}

import React, { createContext, useState, useContext, ReactNode, useEffect } from 'react';
import { PredictedEvent, MarketSentimentResult, ChatMessage, AnalysisResult, DashboardOverview, SeasonalModeSetting, AppNotification } from '../types';

interface PageDataState {
    dashboard: {
        overview: DashboardOverview | null;
        error: string | null;
    };
    predictor: {
        events: PredictedEvent[] | null;
        error: string | null;
    };
    marketNews: {
        result: MarketSentimentResult | null;
        asset: string;
        error: string | null;
    };
    apexAI: {
        messages: ChatMessage[];
    };
    analysisHistory: {
        history: AnalysisResult[];
    };
    seasonalModeSetting: SeasonalModeSetting;
    notifications: AppNotification[];
}

interface PageDataContextType {
    pageData: PageDataState;
    setDashboardData: (data: { overview: DashboardOverview | null; error: string | null; }) => void;
    setPredictorData: (data: { events: PredictedEvent[] | null; error: string | null; }) => void;
    setMarketNewsData: (data: { result: MarketSentimentResult | null; asset: string; error: string | null; }) => void;
    setApexAIMessages: (messages: ChatMessage[] | ((prevMessages: ChatMessage[]) => ChatMessage[])) => void;
    clearApexChat: () => void;
    addAnalysisToHistory: (result: AnalysisResult) => void;
    clearAnalysisHistory: () => void;
    setSeasonalModeSetting: (setting: SeasonalModeSetting) => void;
    dismissNotification: (id: string) => void;
}

const PageDataContext = createContext<PageDataContextType | undefined>(undefined);

const initialState: PageDataState = {
    dashboard: { overview: null, error: null },
    predictor: { events: null, error: null },
    marketNews: { result: null, asset: '', error: null },
    apexAI: { messages: [] },
    analysisHistory: { history: [] },
    seasonalModeSetting: 'Auto',
    notifications: [],
};

export const PageDataProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
    const [pageData, setPageData] = useState<PageDataState>(() => {
        let history: AnalysisResult[] = [];
        let dashboardData = { overview: null, error: null };
        let seasonalSetting: SeasonalModeSetting = 'Auto';

        try {
            const savedHistory = localStorage.getItem('analysisHistory');
            if (savedHistory) {
                const parsedHistory = JSON.parse(savedHistory);
                if (Array.isArray(parsedHistory)) {
                    history = parsedHistory;
                }
            }

            const savedDashboard = localStorage.getItem('dashboardOverview');
            if (savedDashboard) {
                const parsed = JSON.parse(savedDashboard);

                if (parsed && typeof parsed === 'object') {
                    const isSchemaValid = 
                        parsed.dailyBiases && 
                        Array.isArray(parsed.dailyBiases) && 
                        parsed.dailyBiases.length > 0 &&
                        parsed.tradingOpportunities?.highProbabilitySetups?.length >= 2 &&
                        parsed.marketCondition?.dominantSession;

                    if (parsed.lastUpdated && (Date.now() - parsed.lastUpdated < 3600000) && isSchemaValid) {
                        dashboardData = { overview: parsed, error: null };
                    }
                }
            }

            const savedSetting = localStorage.getItem('seasonalModeSetting');
            if (savedSetting === 'Auto' || savedSetting === 'On' || savedSetting === 'Off') {
                seasonalSetting = savedSetting;
            }
        } catch (error) {
            console.error("Failed to parse data from localStorage", error);
            localStorage.removeItem('dashboardOverview');
            localStorage.removeItem('analysisHistory');
            localStorage.removeItem('seasonalModeSetting');
        }
        return { ...initialState, analysisHistory: { history }, dashboard: dashboardData, seasonalModeSetting: seasonalSetting };
    });

    const addNotification = (notif: Omit<AppNotification, 'id'>) => {
        const newNotif = { ...notif, id: new Date().toISOString() };
        setPageData(prev => ({
            ...prev,
            notifications: [newNotif, ...prev.notifications]
        }));
         setTimeout(() => dismissNotification(newNotif.id), 8000);
    };

    useEffect(() => {
        const lastVisitStr = localStorage.getItem('lastVisitDate');
        const today = new Date();
        const todayStr = today.toISOString().split('T')[0];

        if (lastVisitStr !== todayStr) {
            localStorage.setItem('lastVisitDate', todayStr);
            const lastVisitDate = lastVisitStr ? new Date(lastVisitStr) : null;

            if (pageData.seasonalModeSetting === 'Auto' && 
                today.getMonth() === 1 && // February
                today.getDate() === 1 &&
                lastVisitDate &&
                lastVisitDate.getMonth() === 0 // Was January
            ) {
                addNotification({
                    message: '🟢 Seasonal Mode Disabled — Market Normalizing',
                    type: 'success',
                });
            }
        }
    }, []);

    const setDashboardData = (data: { overview: DashboardOverview | null; error: string | null; }) => {
        if (data.overview) {
            localStorage.setItem('dashboardOverview', JSON.stringify(data.overview));
        }
        setPageData(prev => ({ ...prev, dashboard: data }));
    };

    const setPredictorData = (data: { events: PredictedEvent[] | null; error: string | null; }) => {
        setPageData(prev => ({ ...prev, predictor: data }));
    };

    const setMarketNewsData = (data: { result: MarketSentimentResult | null; asset: string; error: string | null; }) => {
        setPageData(prev => ({ ...prev, marketNews: data }));
    };

    const setApexAIMessages = (messages: ChatMessage[] | ((prevMessages: ChatMessage[]) => ChatMessage[])) => {
        setPageData(prev => {
            const newMessages = typeof messages === 'function' ? messages(prev.apexAI.messages) : messages;
            return {
                ...prev,
                apexAI: { ...prev.apexAI, messages: newMessages },
            };
        });
    };

    const clearApexChat = () => {
        setPageData(prev => ({ ...prev, apexAI: { messages: [] } }));
    };

    const addAnalysisToHistory = (result: AnalysisResult) => {
        setPageData(prev => {
            const newHistory = [result, ...prev.analysisHistory.history];
            try {
                localStorage.setItem('analysisHistory', JSON.stringify(newHistory));
            } catch (error) {
                console.error("Failed to save analysis history to localStorage", error);
            }
            return { ...prev, analysisHistory: { history: newHistory } };
        });
    };

    const clearAnalysisHistory = () => {
        try {
            localStorage.removeItem('analysisHistory');
        } catch (error) {
            console.error("Failed to remove analysis history from localStorage", error);
        }
        setPageData(prev => ({ ...prev, analysisHistory: { history: [] } }));
    };

    const setSeasonalModeSetting = (setting: SeasonalModeSetting) => {
        localStorage.setItem('seasonalModeSetting', setting);
        setPageData(prev => ({ ...prev, seasonalModeSetting: setting }));
    };

    const dismissNotification = (id: string) => {
        setPageData(prev => ({
            ...prev,
            notifications: prev.notifications.filter(n => n.id !== id)
        }));
    };

    const value = {
        pageData,
        setDashboardData,
        setPredictorData,
        setMarketNewsData,
        setApexAIMessages,
        clearApexChat,
        addAnalysisToHistory,
        clearAnalysisHistory,
        setSeasonalModeSetting,
        dismissNotification,
    };

    return (
        <PageDataContext.Provider value={value}>
            {children}
        </PageDataContext.Provider>
    );
};

export const usePageData = (): PageDataContextType => {
    const context = useContext(PageDataContext);
    if (!context) {
        throw new Error('usePageData must be used within a PageDataProvider');
    }
    return context;
};

import React, { useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, Outlet } from 'react-router-dom';
import Header from './components/Header';
import Footer from './components/Footer';
import Login from './pages/Login';
import SignUp from './pages/SignUp';
import Landing from './pages/Landing';
import Trader from './pages/Trader';
import Analysis from './pages/Analysis';
import MarketNews from './pages/MarketNews';
import Journal from './pages/Journal';
import History from './pages/History';
import ApexAI from './pages/ApexAI';
import Introduction from './pages/Introduction';
import BotMaker from './pages/BotMaker';
import IndicatorMaker from './pages/IndicatorMaker';
import Pricing from './pages/Pricing';
import Predictor from './pages/Predictor';
import TabbedNav from './components/TabbedNav';
import Notifications from './components/Notifications';
import { AuthProvider, useAuth } from './hooks/useAuth';
import { ThemeProvider } from './hooks/useTheme';
import { EdgeLightingProvider } from './hooks/useEdgeLighting';
import ResponsiveFix from './components/ResponsiveFix';
import { AppContextProvider } from './hooks/useAppContext';
import AIAgent from './components/AIAgent';
import { PageDataProvider } from './hooks/usePageData';
import { EnvironmentProvider, useEnvironment } from './hooks/useEnvironment';
import ErrorLog from './components/ErrorLog';

const App: React.FC = () => {
  return (
    <EnvironmentProvider>
      <AuthProvider>
        <ThemeProvider>
          <EdgeLightingProvider>
            <HashRouter>
              <AppContextProvider>
                <PageDataProvider>
                  <AppContent />
                </PageDataProvider>
              </AppContextProvider>
            </HashRouter>
          </EdgeLightingProvider>
        </ThemeProvider>
      </AuthProvider>
    </EnvironmentProvider>
  );
};

const AppContent: React.FC = () => {
  const environment = useEnvironment();

  useEffect(() => {
    const splashScreen = document.getElementById('splash-screen');
    if (splashScreen) {
      splashScreen.style.opacity = '0';
      splashScreen.addEventListener('transitionend', () => splashScreen.remove());
    }
  }, []);

  return (
    <ResponsiveFix>
      <div className="relative isolate flex flex-col min-h-screen text-gray-800 dark:text-gray-200 font-sans overflow-x-hidden">
        <Notifications />
        <Routes>
          <Route element={<GuestLayout />}>
            <Route path="/" element={<Landing />} />
            <Route path="/login" element={<Login />} />
            <Route path="/signup" element={<SignUp />} />
          </Route>

          <Route element={<ProtectedRoute><AppLayout /></ProtectedRoute>}>
            <Route path="/dashboard" element={<Trader />} />
            <Route path="/analysis" element={<Analysis />} />
            <Route path="/market-news" element={<MarketNews />} />
            <Route path="/predictor" element={<Predictor />} />
            <Route path="/journal" element={<Journal />} />
            <Route path="/history" element={<History />} />
            <Route path="/apex-ai" element={<ApexAI />} />
            <Route path="/coders" element={<CodersPage />} />
          </Route>

          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
        <AIAgent />
        {environment === 'aistudio' && <ErrorLog />}
      </div>
    </ResponsiveFix>
  );
};

const GuestLayout: React.FC = () => {
  const { user } = useAuth();
  if (!user.isGuest) {
    return <Navigate to="/dashboard" />;
  }
  return (
    <>
      <Header />
      <main className="flex-grow w-full flex flex-col py-4 sm:py-6 lg:py-8">
        <div className="w-full max-w-7xl mx-auto px-4 sm:px-6 lg:py-8 flex-1 flex flex-col justify-center">
          <Outlet />
        </div>
      </main>
      <Footer />
    </>
  );
};

const AppLayout: React.FC = () => (
  <>
    <Header />
    <TabbedNav />
    <main className="flex-grow w-full flex flex-col py-4 sm:py-6 lg:py-8">
      <div className="w-full max-w-7xl mx-auto px-4 sm:px-6 lg:py-8 flex-1 flex flex-col justify-center">
        <Outlet />
      </div>
    </main>
    <Footer />
  </>
);

const ProtectedRoute: React.FC<{ children: React.ReactElement }> = ({ children }) => {
  const { user } = useAuth();
  return user.isGuest ? <Navigate to="/login" /> : children;
};

const CodersPage: React.FC = () => (
    <div className="space-y-16">
        <section id="coders"><Introduction /></section>
        <section id="bot-maker"><BotMaker /></section>
        <section id="indicator-maker"><IndicatorMaker /></section>
    </div>
);


export default App;

import React from 'react';
import { usePageData } from '../hooks/usePageData';

const Notifications: React.FC = () => {
  const { pageData, dismissNotification } = usePageData();
  const { notifications } = pageData;

  if (notifications.length === 0) {
    return null;
  }

  const getIconAndColor = (type: 'info' | 'success' | 'warning') => {
      switch (type) {
          case 'success':
              return { icon: 'fa-check-circle', color: 'bg-green-500' };
          case 'warning':
              return { icon: 'fa-exclamation-triangle', color: 'bg-yellow-500' };
          default:
              return { icon: 'fa-info-circle', color: 'bg-blue-500' };
      }
  }

  return (
    <div className="fixed top-20 right-4 z-[100] w-full max-w-sm space-y-2">
      {notifications.map(notif => {
        const { icon, color } = getIconAndColor(notif.type);
        return (
            <div
                key={notif.id}
                className={`relative flex items-center p-4 pr-10 rounded-lg shadow-lg text-white ${color} animate-fade-in-down`}
                role="alert"
            >
                <i className={`fas ${icon} text-xl mr-3`}></i>
                <p className="text-sm font-medium">{notif.message}</p>
                <button
                    onClick={() => dismissNotification(notif.id)}
                    className="absolute top-1/2 right-2 -translate-y-1/2 w-7 h-7 flex items-center justify-center rounded-full hover:bg-white/20 transition-colors"
                    aria-label="Dismiss"
                >
                    &times;
                </button>
            </div>
        );
      })}
      <style>{`
        @keyframes fade-in-down {
            0% { opacity: 0; transform: translateY(-10px); }
            100% { opacity: 1; transform: translateY(0); }
        }
        .animate-fade-in-down { animation: fade-in-down 0.3s ease-out forwards; }
      `}</style>
    </div>
  );
};

export default Notifications;

import React from 'react';
import { usePageData } from '../hooks/usePageData';
import { SeasonalModeSetting } from '../types';

const isDateInSeasonalWindow = (date: Date): boolean => {
    const month = date.getMonth(); // 0-11
    // November (10), December (11), January (0)
    return month >= 10 || month === 0;
};

const SeasonalModeToggle: React.FC = () => {
    const { pageData, setSeasonalModeSetting } = usePageData();
    const { seasonalModeSetting } = pageData;

    const today = new Date();
    const isAutoSeasonal = isDateInSeasonalWindow(today);
    const isSeasonalModeActive = seasonalModeSetting === 'On' || (seasonalModeSetting === 'Auto' && isAutoSeasonal);

    const options: { value: SeasonalModeSetting, label: string }[] = [
        { value: 'Auto', label: 'Auto' },
        { value: 'On', label: 'On' },
        { value: 'Off', label: 'Off' },
    ];

    const getStatusInfo = () => {
        if (isSeasonalModeActive) {
            return { text: 'Active', color: 'text-green-500', pulse: 'pulse' };
        }
        return { text: 'Inactive', color: 'text-red-500', pulse: 'pulse-red' };
    };

    const status = getStatusInfo();

    return (
        <div className="bg-white/40 dark:bg-black/40 backdrop-blur-xl border border-white/30 dark:border-white/10 rounded-xl p-3 flex flex-col sm:flex-row items-center justify-between gap-3">
            <div className="flex items-center gap-3">
                 <i className="fas fa-snowflake text-xl text-blue-500"></i>
                <div>
                    <h3 className="font-bold text-sm">Seasonal Mode</h3>
                    <div className="flex items-center gap-2 text-xs text-gray-500 dark:text-gray-400">
                        <div className={`w-2 h-2 rounded-full ${status.pulse.replace('pulse', 'bg-green-500').replace('-red', ' bg-red-500')}`}></div>
                        <span>Status: <span className={`font-semibold ${status.color}`}>{status.text}</span> {seasonalModeSetting === 'Auto' && '(Auto)'}</span>
                    </div>
                </div>
            </div>
