                                                    {item.bias}
                                                </span>
                                            </div>
                                            <p className="text-xs text-gray-600 dark:text-gray-400 leading-snug">
                                                {item.outlook}
                                            </p>
                                        </div>
                                    ))}
                                </div>
                             </Card>
                        </div>
                    </div>
                </>
            )}
        </section>
    );
};

