const DailyBiasCard: React.FC<{ biases: DailyBias[], isSeasonal: boolean }> = ({ biases, isSeasonal }) => {
    const [currentIndex, setCurrentIndex] = useState(0);
    const [fade, setFade] = useState(false);

    useEffect(() => {
        if (!biases || biases.length === 0) return;
        const interval = setInterval(() => {
            triggerTransition();
        }, 60000); // 1 minute
        return () => clearInterval(interval);
    }, [biases?.length]);

    const triggerTransition = (nextIndex?: number) => {
        if (!biases || biases.length === 0) return;
        setFade(true);
        setTimeout(() => {
            setCurrentIndex(prev => nextIndex !== undefined ? nextIndex : (prev + 1) % biases.length);
