    return (
        <div>
            <ApiKeyModal isOpen={isKeyModalOpen} onClose={() => setIsKeyModalOpen(false)} onSave={setAlphaVantageApiKey} currentKey={alphaVantageApiKey || ''} />
            <div className="text-center mb-8">
