            {!alphaVantageApiKey && (
                 <div className="bg-blue-500/10 dark:bg-blue-900/20 p-3 rounded-lg border border-blue-500/20 dark:border-blue-500/30 flex items-center justify-between gap-3 mb-4">
                    <div className="flex items-start gap-3">
