  messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
  appId: import.meta.env.VITE_FIREBASE_APP_ID
};

// Initialize Firebase only if config is present, otherwise export dummies to prevent crash
const app = configExists ? initializeApp(firebaseConfig) : null;
export const auth = app ? getAuth(app) : null;
export const googleProvider = new GoogleAuthProvider();

import React, { createContext, useState, useContext, useEffect, ReactNode } from 'react';
import { 
  signInWithPopup, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut, 
  onAuthStateChanged,
  User as FirebaseUser
} from 'firebase/auth';
import { auth, googleProvider } from '../services/firebaseConfig';

interface User {
  email?: string;
  plan: 'Free' | 'Pro' | 'Apex';
  isGuest?: boolean;
  uid?: string;
}

interface AuthContextType {
  user: User;
  login: (email: string, password?: string) => Promise<void>;
  loginWithGoogle: () => Promise<void>;
  signup: (email: string, password?: string) => Promise<void>;
  logout: () => void;
  error: string | null;
  clearError: () => void;
  isLoading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User>({ plan: 'Free', isGuest: true });
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (!auth) {
      console.warn("Firebase config not found. Running in Guest Mode.");
      setIsLoading(false);
      return;
    }

    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      if (firebaseUser) {
        setUser({
          email: firebaseUser.email || undefined,
          uid: firebaseUser.uid,
          plan: 'Free', // Default plan, in a real app this would come from a DB
          isGuest: false
        });
      } else {
        setUser({ plan: 'Free', isGuest: true });
      }
      setIsLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const clearError = () => setError(null);

  const login = async (email: string, password?: string) => {
    setError(null);
    if (!auth) {
        setError("Firebase not configured.");
        throw new Error("Firebase not configured");
    }
    if (!password) {
      setError("Password is required.");
      throw new Error("Password is required");
    }
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (err: any) {
      console.error("Login failed", err);
      let msg = "Failed to login.";
      if (err.code === 'auth/invalid-credential') msg = "Invalid email or password.";
      if (err.code === 'auth/user-not-found') msg = "User not found.";
      if (err.code === 'auth/wrong-password') msg = "Invalid password.";
      setError(msg);
      throw err;
    }
  };

  const loginWithGoogle = async () => {
      setError(null);
      if (!auth) {
          setError("Firebase not configured. Please add VITE_FIREBASE keys to .env");
          return;
      }
      try {
          await signInWithPopup(auth, googleProvider);
      } catch (err: any) {
          console.error("Google Login failed", err);
          if (err.code !== 'auth/popup-closed-by-user') {
             setError(err.message || "Google sign-in failed.");
          }
          throw err;
      }
  };

  const signup = async (email: string, password?: string) => {
    setError(null);
    if (!auth) {
        setError("Firebase not configured.");
        throw new Error("Firebase not configured");
    }
    if (!password) {
        setError("Password is required.");
        throw new Error("Password is required");
    }
    try {
        await createUserWithEmailAndPassword(auth, email, password);
    } catch (err: any) {
        console.error("Signup failed", err);
        let msg = "Failed to create account.";
        if (err.code === 'auth/email-already-in-use') msg = "Email already in use.";
        if (err.code === 'auth/weak-password') msg = "Password should be at least 6 characters.";
        setError(msg);
        throw err;
    }
  };

  const logout = async () => {
    if (auth) {
        await signOut(auth);
    }
    setUser({ plan: 'Free', isGuest: true });
    setError(null);
  };

  return (
    <AuthContext.Provider value={{ user, login, loginWithGoogle, signup, logout, error, clearError, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

