    if (environment !== 'aistudio' || !ai) return "Auto-fix is only available in the AI Studio environment.";
    const errorLog = errors.map(e => `Type: ${e.type}\nMessage: ${e.message}\nStack: ${e.stack || 'N/A'}`).join('\n\n---\n\n');
