  }, [theme]);

  return (
    <div className="tradingview-widget-container w-full h-[600px] md:h-[700px] lg:h-[800px]" ref={container}>
      <div className="tradingview-widget-container__widget" style={{ height: "100%", width: "100%" }}></div>
