const ValueRow: React.FC<{ label: string, value: string, onCopy: () => void, copied: boolean, isLoss?: boolean, isWin?: boolean }> = ({ label, value, onCopy, copied, isLoss, isWin }) => {
    let valueColor = "text-white";
