    if (isWin) valueColor = "text-green-400";

    return (
        <div className="flex justify-between items-center group bg-black/20 p-2 rounded hover:bg-black/30 transition-colors">
            <span className="text-xs text-gray-500 font-bold uppercase tracking-wider">{label}</span>
            <div className="flex items-center gap-2">
                <span className={`font-mono font-bold text-sm ${valueColor}`}>{value}</span>
                <button 
                    onClick={onCopy}
                    className="w-6 h-6 flex items-center justify-center rounded bg-white/5 hover:bg-white/10 text-gray-400 hover:text-white transition-colors"
                    title="Copy value"
                >
                    {copied ? <i className="fas fa-check text-green-500 text-xs"></i> : <i className="far fa-copy text-xs"></i>}
                </button>
            </div>
        </div>
    )
}

const SignalOverlay: React.FC = () => {
  const { pageData } = usePageData();
  // Get the most recent analysis from history
  const latestAnalysis = pageData.analysisHistory.history[0];

  const [isOpen, setIsOpen] = useState(true);
  const [isCopied, setIsCopied] = useState<string | null>(null);

  if (!latestAnalysis) return null; // Don't show anything if history is empty

  const handleCopy = (text: string, label: string) => {
    navigator.clipboard.writeText(text);
    setIsCopied(label);
    setTimeout(() => setIsCopied(null), 2000);
  };

  const isBuy = latestAnalysis.signal === 'BUY';
  const isSell = latestAnalysis.signal === 'SELL';

  const borderColor = isBuy ? 'border-green-500' : isSell ? 'border-red-500' : 'border-gray-500';
  const textColor = isBuy ? 'text-green-500' : isSell ? 'text-red-500' : 'text-gray-500';
  const bgColor = isBuy ? 'bg-green-500/20' : isSell ? 'bg-red-500/20' : 'bg-gray-500/20';
  const icon = isBuy ? 'fa-arrow-up' : isSell ? 'fa-arrow-down' : 'fa-minus';

  // Format data for display
  const entryDisplay = latestAnalysis.entryPriceRange && latestAnalysis.entryPriceRange.length > 0 
    ? latestAnalysis.entryPriceRange[0] 
    : 'N/A';

  const tpDisplay = Array.isArray(latestAnalysis.takeProfits) 
    ? latestAnalysis.takeProfits[0] 
    : latestAnalysis.takeProfits || 'N/A';

  // If minimized, show a small floating button
  if (!isOpen) {
      return (
          <button 
            onClick={() => setIsOpen(true)}
            className="absolute top-4 right-4 z-40 bg-gray-900/80 backdrop-blur-md border border-white/20 p-3 rounded-xl shadow-lg hover:bg-gray-800 transition-all group animate-fade-in"
            title="Show Signal Overlay"
          >
              <i className="fas fa-layer-group text-gray-400 group-hover:text-white text-lg"></i>
              <span className="absolute -top-1 -right-1 w-3 h-3 bg-red-500 rounded-full animate-pulse"></span>
          </button>
      );
  }

  return (
    <div className="absolute top-4 right-4 z-40 w-80 bg-[#0C0F1A]/95 backdrop-blur-xl border border-white/10 rounded-2xl shadow-2xl overflow-hidden animate-fade-in-left">
      {/* Header */}
      <div className="p-4 border-b border-white/5 flex justify-between items-center bg-gradient-to-r from-white/5 to-transparent">
        <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${isBuy ? 'bg-green-500' : isSell ? 'bg-red-500' : 'bg-gray-500'} animate-pulse`}></div>
            <span className="text-sm font-bold text-gray-200 uppercase tracking-wide">Active Setup</span>
        </div>
        <button onClick={() => setIsOpen(false)} className="text-gray-500 hover:text-white transition-colors p-1">
            <i className="fas fa-minus text-xs"></i>
        </button>
      </div>

      {/* Body */}
      <div className="p-5 space-y-5">

        {/* Signal Header */}
        <div className="flex justify-between items-start">
            <div>
                <h3 className="text-xl font-extrabold text-white tracking-tight">{latestAnalysis.asset}</h3>
                <p className="text-xs text-gray-400 mt-1 font-medium">{latestAnalysis.timeframe} • {latestAnalysis.date.split(',')[0]}</p>
            </div>
            <div className={`flex flex-col items-end`}>
                <div className={`px-3 py-1 rounded-lg border ${borderColor} ${bgColor} ${textColor} text-sm font-black flex items-center gap-2 shadow-lg`}>
                    <i className={`fas ${icon}`}></i>
                    {latestAnalysis.signal}
                </div>
            </div>
        </div>

        {/* Values */}
        <div className="space-y-2">
            <ValueRow 
                label="Entry Price" 
                value={entryDisplay} 
                onCopy={() => handleCopy(entryDisplay, 'entry')} 
                copied={isCopied === 'entry'} 
            />
            <ValueRow 
                label="Stop Loss" 
                value={latestAnalysis.stopLoss} 
                onCopy={() => handleCopy(latestAnalysis.stopLoss, 'sl')} 
                copied={isCopied === 'sl'}
                isLoss 
            />
            <ValueRow 
                label="Take Profit" 
                value={tpDisplay} 
                onCopy={() => handleCopy(tpDisplay, 'tp')} 
                copied={isCopied === 'tp'}
                isWin 
            />
        </div>

        {/* Confidence Meter */}
        <div className="bg-black/40 rounded-lg p-3 border border-white/5">
            <div className="flex justify-between text-xs text-gray-400 mb-2 font-medium">
                <span>AI Confidence</span>
                <span className="text-white">{latestAnalysis.confidence}%</span>
            </div>
            <div className="h-2 bg-gray-700 rounded-full overflow-hidden">
                <div 
                    className={`h-full ${latestAnalysis.confidence > 75 ? 'bg-gradient-to-r from-green-500 to-emerald-400' : 'bg-gradient-to-r from-yellow-500 to-orange-400'} transition-all duration-1000`} 
                    style={{ width: `${latestAnalysis.confidence}%` }}
                ></div>
            </div>
        </div>

        <div className="text-[10px] text-gray-600 text-center italic">
            Use the Charting tools to plot these coordinates.
        </div>
      </div>
      <style>{`
        @keyframes fade-in-left {
            0% { opacity: 0; transform: translateX(20px); }
            100% { opacity: 1; transform: translateX(0); }
        }
        .animate-fade-in-left { animation: fade-in-left 0.3s ease-out forwards; }
      `}</style>
    </div>
  );
};

